#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_VERTICES 100

/* ==================== UNDIRECTED GRAPH ==================== */

typedef struct {
 int n; // Number of vertices
 int adj[MAX_VERTICES][MAX_VERTICES];
 int adjList[MAX_VERTICES][MAX_VERTICES]; // Adjacency list
 int adjSize[MAX_VERTICES]; // Size of each adjacency list
} UndirectedGraph;

// Initialize undirected graph
void initUndirectedGraph(UndirectedGraph* g, int n) {
 g->n = n;
 for (int i = 0; i < n; i++) {
 g->adjSize[i] = 0;
 for (int j = 0; j < n; j++) {
 g->adj[i][j] = 0;
 }
 }
}

// Add undirected edge
void addEdge(UndirectedGraph* g, int u, int v) {
 g->adj[u][v] = 1;
 g->adj[v][u] = 1;
 g->adjList[u][g->adjSize[u]++] = v;
 g->adjList[v][g->adjSize[v]++] = u;
}

// DFS for connected components
void dfsComponent(UndirectedGraph* g, int v, bool visited[], int component[]) {
 static int compId = 0;
 visited[v] = true;
 component[v] = compId;

 // Visit all neighbors
 for (int i = 0; i < g->adjSize[v]; i++) {
 int neighbor = g->adjList[v][i];
 if (!visited[neighbor]) {
 dfsComponent(g, neighbor, visited, component);
 }
 }
}

// Find all connected components
int findConnectedComponents(UndirectedGraph* g, int component[]) {
 bool visited[MAX_VERTICES] = {false};
 int componentCount = 0;

 for (int v = 0; v < g->n; v++) {
 if (!visited[v]) {
 componentCount++;
 // Use a hack to pass componentId to recursive function
 // In practice, use a global or pass as pointer
 static int currentComp;
 currentComp = componentCount;

 // Simple DFS with component tracking
 int stack[MAX_VERTICES];
 int top = -1;

 stack[++top] = v;
 visited[v] = true;

 while (top >= 0) {
 int current = stack[top--];
 component[current] = componentCount;

 for (int i = 0; i < g->adjSize[current]; i++) {
 int neighbor = g->adjList[current][i];
 if (!visited[neighbor]) {
 visited[neighbor] = true;
 stack[++top] = neighbor;
 }
 }
 }
 }
 }

 return componentCount;
}


/* ==================== DIRECTED GRAPH (Kosaraju) ==================== */

typedef struct {
 int n; // Number of vertices
 int adj[MAX_VERTICES][MAX_VERTICES];
 int adjSize[MAX_VERTICES];
} DirectedGraph;

void initDirectedGraph(DirectedGraph* g, int n) {
 g->n = n;
 for (int i = 0; i < n; i++) {
 g->adjSize[i] = 0;
 for (int j = 0; j < n; j++) {
 g->adj[i][j] = 0;
 }
 }
}

void addDirectedEdge(DirectedGraph* g, int u, int v) {
 g->adj[u][v] = 1;
 g->adjList[u][g->adjSize[u]++] = v;
}

// First DFS: Fill stack with vertices in finish order
void dfs1(DirectedGraph* g, int v, bool visited[], int stack[], int* top) {
 visited[v] = true;

 for (int i = 0; i < g->adjSize[v]; i++) {
 int neighbor = g->adjList[v][i];
 if (!visited[neighbor]) {
 dfs1(g, neighbor, visited, stack, top);
 }
 }
 stack[++*top] = v;
}

// Second DFS: On transpose graph, collect SCC vertices
void dfs2(DirectedGraph* g, int v, bool visited[], int scc[], int* sccSize) {
 visited[v] = true;
 scc[*sccSize] = v;
 (*sccSize)++;

 // Use transpose adjacency (stored during edge addition)
 for (int i = 0; i < g->adjSize[v]; i++) {
 int neighbor = g->adjList[v][i];
 // Check if edge exists in transpose (i.e., original had reverse)
 }
}

// Kosaraju's Algorithm
int kosarajuSCC(DirectedGraph* g, int sccComponents[]) {
 bool visited[MAX_VERTICES] = {false};
 int stack[MAX_VERTICES];
 int top = -1;

 // Step 1: First DFS to get finish order
 for (int v = 0; v < g->n; v++) {
 if (!visited[v]) {
 dfs1(g, v, visited, stack, &top);
 }
 }

 // Build transpose graph
 DirectedGraph gt;
 initDirectedGraph(&gt, g->n);
 for (int i = 0; i < g->n; i++) {
 for (int j = 0; j < g->adjSize[i]; j++) {
 int neighbor = g->adjList[i][j];
 // Add reverse edge
 gt.adjList[neighbor][gt.adjSize[neighbor]++] = i;
 }
 }

 // Step 2: Second DFS on transpose in reverse finish order
 bool visited2[MAX_VERTICES] = {false};
 int sccCount = 0;
 int scc[MAX_VERTICES];
 int sccSize;

 while (top >= 0) {
 int v = stack[top--];
 if (!visited2[v]) {
 sccSize = 0;

 // DFS on transpose graph from v
 int stack2[MAX_VERTICES];
 int top2 = -1;
 stack2[++top2] = v;
 visited2[v] = true;

 while (top2 >= 0) {
 int current = stack2[top2--];
 scc[sccSize++] = current;

 for (int i = 0; i < gt.adjSize[current]; i++) {
 int neighbor = gt.adjList[current][i];
 if (!visited2[neighbor]) {
 visited2[neighbor] = true;
 stack2[++top2] = neighbor;
 }
 }
 }

 // Store SCC
 for (int i = 0; i < sccSize; i++) {
 sccComponents[scc[i]] = sccCount;
 }
 sccCount++;
 }
 }

 return sccCount;
}


/* ==================== MAIN DEMONSTRATION ==================== */

int main {
 printf("==================================================\n");
 printf("Demo: Finding Connected Components in C\n");
 printf("==================================================\n\n");

 // Create graph from Figure 2 (disconnected graph)
 // Components: {0,1,2}, {3}, {4,5,6}
 UndirectedGraph g;
 initUndirectedGraph(&g, 7);

 // Component 1: 0 -- 1, 0 -- 2
 addEdge(&g, 0, 1);
 addEdge(&g, 0, 2);

 // Vertex 3 is isolated

 // Component 2: 4 -- 5, 4 -- 6
 addEdge(&g, 4, 5);
 addEdge(&g, 4, 6);

 int component[MAX_VERTICES];
 int count = findConnectedComponents(&g, component);

 printf("Undirected Graph (7 vertices)\n");
 printf("Edges: (0,1), (0,2), (4,5), (4,6)\n\n");
 printf("Number of connected components: %d\n", count);
 printf("Component assignments:\n");
 for (int v = 0; v < 7; v++) {
 printf(" Vertex %d -> Component %d\n", v, component[v]);
 }

 // Demo Kosaraju's Algorithm
 printf("\n==================================================\n");
 printf("Demo: Kosaraju's Algorithm for SCCs\n");
 printf("==================================================\n\n");

 DirectedGraph dg;
 initDirectedGraph(&dg, 5);

 // Create graph from Figure 3
 // SCC: {0,1,2,3}, single vertex: {4}
 addDirectedEdge(&dg, 0, 1);
 addDirectedEdge(&dg, 1, 2);
 addDirectedEdge(&dg, 2, 3);
 addDirectedEdge(&dg, 3, 0); // Creates cycle
 addDirectedEdge(&dg, 2, 4);

 int sccComp[MAX_VERTICES];
 int sccCount = kosarajuSCC(&dg, sccComp);

 printf("Directed Graph (5 vertices)\n");
 printf("Edges: 0->1, 1->2, 2->3, 3->0, 2->4\n\n");
 printf("Number of SCCs: %d\n", sccCount);
 printf("SCC assignments:\n");
 for (int v = 0; v < 5; v++) {
 printf(" Vertex %d -> SCC %d\n", v, sccComp[v]);
 }

 printf("\n==================================================\n");
 printf("Time Complexities:\n");
 printf("==================================================\n");
 printf("Connected Components (DFS): O(V + E)\n");
 printf("Kosaraju's SCC: O(V + E)\n");
 printf("Space Complexity: O(V + E)\n");

 return 0;
}
